# -*- coding: utf-8 -*-
"""(English, Malayalam, transliteration) tuples for chapters 518–590. Part 2 in malayalam_remainder_data2.py"""
from malayalam_lesson_content import R, _pad


def D(*triples):
    return _pad([R(e, m, r) for e, m, r in triples], n=20)


